from pymodbus.client import ModbusTcpClient
import time

client = ModbusTcpClient('192.168.1.1', port=502, timeout=3)
connected = client.connect()
print(f'연결: {connected}')

if connected:
    # 스크루드라이버 Modbus 레지스터 탐색
    # OnRobot Compute Box는 보통 0~255 범위에 디바이스 상태를 매핑

    print('\n=== Holding Registers (FC03) 스캔 ===')
    for start in range(0, 300, 10):
        try:
            t = time.time()
            result = client.read_holding_registers(start, 10, slave=65)
            elapsed = time.time() - t
            if not result.isError():
                vals = result.registers
                if any(v != 0 for v in vals):
                    print(f'  [{start:3d}~{start+9:3d}] {vals}  ({elapsed:.3f}s)')
        except Exception as e:
            pass

    # slave=0 (broadcast) 도 시도
    print('\n=== slave=0 ===')
    for start in range(0, 300, 10):
        try:
            result = client.read_holding_registers(start, 10, slave=0)
            if not result.isError():
                vals = result.registers
                if any(v != 0 for v in vals):
                    print(f'  [{start:3d}~{start+9:3d}] {vals}')
        except:
            pass

    # slave=1도 시도
    print('\n=== slave=1 ===')
    for start in range(0, 300, 10):
        try:
            result = client.read_holding_registers(start, 10, slave=1)
            if not result.isError():
                vals = result.registers
                if any(v != 0 for v in vals):
                    print(f'  [{start:3d}~{start+9:3d}] {vals}')
        except:
            pass

