from pymodbus.client import ModbusTcpClient
import time

client = ModbusTcpClient('192.168.1.1', port=502, timeout=2)
client.connect()

# 다양한 slave ID 시도
print('=== Slave ID 스캔 (HR 0~9) ===')
for sid in [0, 1, 2, 65, 100, 200, 255]:
    try:
        r = client.read_holding_registers(0, 10, slave=sid)
        if not r.isError():
            print(f'  slave={sid}: {r.registers}')
        else:
            print(f'  slave={sid}: ERROR {r}')
    except Exception as e:
        print(f'  slave={sid}: {type(e).__name__}')

# 넓은 범위 스캔 (slave=65, OnRobot 기본)
print('\n=== slave=65 HR 0~1000 (0이 아닌 값만) ===')
for start in range(0, 1000, 10):
    try:
        r = client.read_holding_registers(start, 10, slave=65)
        if not r.isError() and any(v != 0 for v in r.registers):
            print(f'  [{start:4d}~{start+9:4d}] {r.registers}')
    except:
        pass

# Input Registers (FC04)
print('\n=== slave=65 IR 0~500 ===')
for start in range(0, 500, 10):
    try:
        r = client.read_input_registers(start, 10, slave=65)
        if not r.isError() and any(v != 0 for v in r.registers):
            print(f'  [{start:4d}~{start+9:4d}] {r.registers}')
    except:
        pass

# Coils (FC01)
print('\n=== slave=65 Coils 0~200 ===')
for start in range(0, 200, 10):
    try:
        r = client.read_coils(start, 10, slave=65)
        if not r.isError() and any(r.bits[:10]):
            print(f'  [{start:3d}~{start+9:3d}] {r.bits[:10]}')
    except:
        pass

# slave=1 넓은 범위
print('\n=== slave=1 HR 0~1000 ===')
for start in range(0, 1000, 10):
    try:
        r = client.read_holding_registers(start, 10, slave=1)
        if not r.isError() and any(v != 0 for v in r.registers):
            print(f'  [{start:4d}~{start+9:4d}] {r.registers}')
    except:
        pass

client.close()
print('\n완료')
" 2>&1

