    try:
        r = client.read_holding_registers(start, count=10, device_id=65)
        if hasattr(r, 'registers'):
            vals = r.registers
            if any(v != 0 for v in vals):
                print(f'  [{start:4d}~{start+9:4d}] {vals}')
    except:
        pass

print('\n=== device_id=65 Input Registers 스캔 ===')
for start in range(0, 500, 10):
    try:
        r = client.read_input_registers(start, count=10, device_id=65)
        if hasattr(r, 'registers'):
            vals = r.registers
            if any(v != 0 for v in vals):
                print(f'  [{start:4d}~{start+9:4d}] {vals}')
    except:
        pass

print('\n=== device_id=65 Coils 스캔 ===')
for start in range(0, 200, 10):
    try:
        r = client.read_coils(start, count=10, device_id=65)
        if hasattr(r, 'bits'):
            bits = r.bits[:10]
            if any(bits):
                print(f'  [{start:3d}~{start+9:3d}] {bits}')
    except:
        pass

# 속도 테스트
print('\n=== Modbus 읽기 속도 테스트 ===')
times = []
for i in range(10):
    t = time.time()
    r = client.read_holding_registers(0, count=1, device_id=65)
    elapsed = time.time() - t
    times.append(elapsed)
avg = sum(times)/len(times)
print(f'  10회 평균: {avg*1000:.1f}ms (최소 {min(times)*1000:.1f}ms, 최대 {max(times)*1000:.1f}ms)')

client.close()
" 2>&1

